1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
4	
5	const CURSE_SURCHARGE = 0.5;
6	const HIGH_ENCHANT_SURCHARGE = 0.3;
7	const HIGH_ENCHANT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT = 0.2;
9	const LOYALTY_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE = 0.1;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
14	const HIGH_ENCHANT_REIMBURSEMENT_RATE = 0.5;
15	const FULL_REIMBURSEMENT_RATE = 1;
16	
17	type Customer = { yearsWithMHPCO: number };
18	type Damage = { itemType: string; amount: number };
19	type Incident = { cause: string; damages: Damage[] };
20	type QuoteStep = { op: "quote"; items: Item[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	type QuoteResult = { premium: number };
25	type ClaimResult = { payout: number; remainingCap: number };
26	type StepResult = QuoteResult | ClaimResult;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const INSURANCE_VALUES: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_PREMIUM = 60;
48	const BLOCK_SIZE = 3;
49	
50	const itemSurcharge = (item: Item): number => {
51	  const base = BASE_PREMIUMS[item.type];
52	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
53	  const enchantSurcharge =
54	    (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE : 0;
55	  return curseSurcharge + enchantSurcharge;
56	};
57	
58	const policyBasePremium = (items: Item[]): number => {
59	  const componentCounts: Record<string, number> = {};
60	  let total = 0;
61	  for (const item of items) {
62	    if (COMPONENT_TYPES.has(item.type)) {
63	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
64	    } else {
65	      total += BASE_PREMIUMS[item.type];
66	    }
67	  }
68	  for (const type of Object.keys(componentCounts)) {
69	    const count = componentCounts[type];
70	    if (count === BLOCK_SIZE) {
71	      total += BLOCK_PREMIUM;
72	    } else {
73	      total += count * BASE_PREMIUMS[type];
74	    }
75	  }
76	  return total;
77	};
78	
79	const insuranceSum = (items: Item[]): number =>
80	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
81	
82	const validateItems = (items: Item[]): void => {
83	  for (const item of items) {
84	    if (!(item.type in BASE_PREMIUMS)) {
85	      throw new Error(`Unknown item type: ${item.type}`);
86	    }
87	  }
88	};
89	
90	const quote = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
91	  validateItems(items);
92	  const base = policyBasePremium(items);
93	  const surcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
94	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? -base * LOYALTY_DISCOUNT : 0;
95	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
96	  const followUp = isFollowUp ? -base * FOLLOW_UP_DISCOUNT : 0;
97	  const premium = Math.ceil(base + surcharges + loyalty + firstInsurance + followUp + PROCESSING_FEE);
98	  return { premium };
99	};
100	
101	type Policy = {
102	  items: Item[];
103	  remainingCap: number;
104	};
105	
106	const reimbursementRate = (item: Item): number =>
107	  (item.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD
108	    ? HIGH_ENCHANT_REIMBURSEMENT_RATE
109	    : FULL_REIMBURSEMENT_RATE;
110	
111	const damagePayout = (damage: Damage, item: Item): number =>
112	  Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
113	
114	const findInsuredItem = (policy: Policy, damage: Damage): Item | undefined =>
115	  policy.items.find((item) => item.type === damage.itemType);
116	
117	const countBy = <T>(items: T[], getType: (item: T) => string): Record<string, number> => {
118	  const counts: Record<string, number> = {};
119	  for (const item of items) {
120	    const type = getType(item);
121	    counts[type] = (counts[type] ?? 0) + 1;
122	  }
123	  return counts;
124	};
125	
126	const validateDamages = (incident: Incident, policy: Policy): void => {
127	  const insuredCounts = countBy(policy.items, (item) => item.type);
128	  const damageCounts = countBy(incident.damages, (damage) => damage.itemType);
129	  for (const type of Object.keys(damageCounts)) {
130	    if ((insuredCounts[type] ?? 0) < damageCounts[type]) {
131	      throw new Error(`Claim has more ${type} damages than insured`);
132	    }
133	  }
134	};
135	
136	const grossPayout = (incident: Incident, policy: Policy): number =>
137	  incident.damages.reduce((sum, damage) => {
138	    const item = findInsuredItem(policy, damage);
139	    return item ? sum + damagePayout(damage, item) : sum;
140	  }, 0);
141	
142	const claim = (incident: Incident, policy: Policy): ClaimResult => {
143	  validateDamages(incident, policy);
144	  const payout = Math.floor(Math.min(grossPayout(incident, policy), policy.remainingCap));
145	  policy.remainingCap -= payout;
146	  return { payout, remainingCap: policy.remainingCap };
147	};
148	
149	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
150	  let quoteCount = 0;
151	  const policies: Record<number, Policy> = {};
152	  const results: StepResult[] = scenario.steps.map((step, index) => {
153	    if (step.op === "quote") {
154	      const isFollowUp = quoteCount > 0;
155	      quoteCount += 1;
156	      const sum = insuranceSum(step.items);
157	      policies[index] = { items: step.items, remainingCap: sum * 2 };
158	      return quote(step.items, scenario.customer, isFollowUp);
159	    } else {
160	      return claim(step.incident, policies[step.policy]);
161	    }
162	  });
163	  return { results };
164	};
